hw.module @add_two_no_carry(in %a : i8, in %b : i8, out sum : i8) {
    %0 = comb.add %a, %b : i8
    hw.output %0 : i8
}

hw.module @add_two_with_carry(in %a : i8, in %b : i8, out sum : i9) {
    %false = hw.constant false
    %0 = comb.concat %false, %a : i1, i8
    %1 = comb.concat %false, %b : i1, i8
    %2 = comb.add %0, %1 : i9
    hw.output %2 : i9
}
